use online_food_del;
-- Summary query
-- 1. Total orders per city.
select r.city,count(o.order_id) as total_orders
from orders o
join resturant r
on o.restaurant_id = r.resturant_id
group by city
order by total_orders desc;
-- 2. revenue generated by each food items.
select m.item_name,sum(m.price * od.quantity) as total_revenue
from menu_item m
join order_detail od 
on m.item_id = od.item_id
group by m.item_name
order by total_revenue desc;